import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom"; // Para redirigir a NewGamePage
import "../styles/mainmenu/LeagueMenu.css";

function LeagueMenu() {
    const navigate = useNavigate(); // Hook para redirigir
    const [jornadas, setJornadas] = useState([]); // Inicializar como array vacío
    const [clasificacion, setClasificacion] = useState([]); // Inicializar como array vacío
    const [jornadaActual, setJornadaActual] = useState(0);
    const [modalVisible, setModalVisible] = useState(false);
    const [modalType, setModalType] = useState(""); // "jornada" o "clasificacion"
    const [equiposSeleccionados, setEquiposSeleccionados] = useState([]);
    const [resultados, setResultados] = useState([]);

    const NUMERO_DESCENSO = 3; // Número de equipos en puestos de descenso

    useEffect(() => {
        // Cargar las jornadas y la clasificación desde localStorage
        const calendario = JSON.parse(localStorage.getItem("calendario")) || []; // Si no hay datos, usar []
        const clasificacionData = JSON.parse(localStorage.getItem("clasificacion")) || []; // Si no hay datos, usar []
        const equipos = JSON.parse(localStorage.getItem("equipos")) || [];
        const seleccionados = equipos.filter((equipo) => equipo.player);
        setEquiposSeleccionados(seleccionados);
        setJornadas(calendario);
        setClasificacion(clasificacionData);
        const resultadosIniciales = calendario.map((jornada) =>
            jornada.map(() => ({ local: null, visitante: null }))
        );
        setResultados(resultadosIniciales);
    }, []);

    const jugarPartido = (local, visitante) => {
        const golesLocal = Math.floor(Math.random() * 5);
        const golesVisitante = Math.floor(Math.random() * 5);

        return { golesLocal, golesVisitante };
    };

    const jugarJornada = (jornadaIndex) => {
        const nuevaJornada = [...jornadas[jornadaIndex]];

        nuevaJornada.forEach((partido, index) => {
            const { local, visitante } = partido;

            if (
                equiposSeleccionados.some((e) => e.id === local.id) ||
                equiposSeleccionados.some((e) => e.id === visitante.id)
            ) {
                // Si el partido involucra un equipo seleccionado, jugar manualmente
                const resultado = jugarPartido(local, visitante);
                nuevaJornada[index] = { ...partido, ...resultado };
            } else {
                // Simular el partido
                const resultado = jugarPartido(local, visitante);
                nuevaJornada[index] = { ...partido, ...resultado };
            }
        });

        const nuevasJornadas = [...jornadas];
        nuevasJornadas[jornadaIndex] = nuevaJornada;
        setJornadas(nuevasJornadas);

        // Actualizar resultados
        const nuevosResultados = [...resultados];
        nuevosResultados[jornadaIndex] = nuevaJornada.map((partido) => ({
            local: partido.golesLocal,
            visitante: partido.golesVisitante,
        }));
        setResultados(nuevosResultados);

        // Actualizar clasificación
        actualizarClasificacion(nuevaJornada);
    };

    const actualizarClasificacion = (jornada) => {
        const nuevaClasificacion = [...clasificacion];

        jornada.forEach(({ local, visitante, golesLocal, golesVisitante }) => {
            const equipoLocal = nuevaClasificacion.find((e) => e.id === local.id);
            const equipoVisitante = nuevaClasificacion.find((e) => e.id === visitante.id);

            equipoLocal.partidosJugados += 1;
            equipoVisitante.partidosJugados += 1;

            equipoLocal.golesFavor += golesLocal;
            equipoLocal.golesContra += golesVisitante;
            equipoVisitante.golesFavor += golesVisitante;
            equipoVisitante.golesContra += golesLocal;

            if (golesLocal > golesVisitante) {
                equipoLocal.victorias += 1;
                equipoLocal.puntos += 3;
                equipoVisitante.derrotas += 1;
            } else if (golesLocal < golesVisitante) {
                equipoVisitante.victorias += 1;
                equipoVisitante.puntos += 3;
                equipoLocal.derrotas += 1;
            } else {
                equipoLocal.empates += 1;
                equipoVisitante.empates += 1;
                equipoLocal.puntos += 1;
                equipoVisitante.puntos += 1;
            }
        });

        setClasificacion(nuevaClasificacion);
        localStorage.setItem("clasificacion", JSON.stringify(nuevaClasificacion));
    };

    const elegirEquipo = (local, visitante) => {
        const equipoElegido = window.confirm(`¿Quieres jugar como ${local.nombre}?`);
        return equipoElegido ? local : visitante;
    };

    const abrirModal = (type) => {
        setModalType(type);
        setModalVisible(true);
    };

    const cerrarModal = () => {
        setModalVisible(false);
    };

    const siguienteJornada = () => {
        if (jornadaActual < jornadas.length - 1) {
            setJornadaActual(jornadaActual + 1);
        }
    };

    const anteriorJornada = () => {
        if (jornadaActual > 0) {
            setJornadaActual(jornadaActual - 1);
        }
    };

    const iniciarPartido = (local, visitante) => {
        // Redirigir a NewGamePage con los datos de los equipos
        navigate("/new-game", { state: { local, visitante } });
    };

    return (
        <div className="league-menu">
            <h1>League Menu</h1>

            <div className="previews-container">
                {/* Preview de la Jornada */}
                <div className="jornada-preview-container" onClick={() => abrirModal("jornada")}>
                    <h2>Jornada {jornadaActual + 1}</h2>
                    <div className="jornada-preview">
                        {jornadas[jornadaActual]?.slice(0, 3).map((partido, index) => (
                            <div key={index} className="partido-preview">
                                <div className="equipo">
                                    <img
                                        src={partido.local?.imagen || "/assets/images/default.png"}
                                        alt={partido.local?.nombre || "Equipo Local"}
                                        className="escudo"
                                    />
                                    <span>{partido.local?.nombre || "Equipo Local"}</span>
                                </div>
                                <span className="vs">vs</span>
                                <div className="equipo">
                                    <img
                                        src={partido.visitante?.imagen || "/assets/images/default.png"}
                                        alt={partido.visitante?.nombre || "Equipo Visitante"}
                                        className="escudo"
                                    />
                                    <span>{partido.visitante?.nombre || "Equipo Visitante"}</span>
                                </div>
                                <button onClick={() => iniciarPartido(partido.local, partido.visitante)}>
                                    Jugar Partido
                                </button>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Preview de la Clasificación */}
                <div className="clasificacion-preview-container" onClick={() => abrirModal("clasificacion")}>
                    <h2>Clasificación</h2>
                    <div className="clasificacion-preview">
                        {clasificacion.slice(0, 5).map((equipo, index) => (
                            <div key={index} className="equipo-clasificacion-preview">
                                <span>{index + 1}.</span>
                                <img
                                    src={equipo.imagen || "/assets/images/default.png"}
                                    alt={equipo.nombre || "Equipo"}
                                    className="escudo"
                                />
                                <span>{equipo.nombre || "Equipo"}</span>
                                <span>{equipo.puntos || 0} pts</span>
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            {/* Modal */}
            {modalVisible && (
                <div className="modal-overlay" onClick={cerrarModal}>
                    <div
                        className="modal-content"
                        onClick={(e) => e.stopPropagation()} // Evitar cerrar al hacer clic dentro del modal
                    >
                        {modalType === "jornada" && (
                            <>
                                <h2>Jornada {jornadaActual + 1} de {jornadas.length}</h2>
                                <div className="jornada-detalle">
                                    {jornadas[jornadaActual]?.map((partido, index) => (
                                        <div key={index} className="partido">
                                            <div className="equipo">
                                                <img
                                                    src={partido.local?.imagen || "/assets/images/default.png"}
                                                    alt={partido.local?.nombre || "Equipo Local"}
                                                    className="escudo"
                                                />
                                                <span>{partido.local?.nombre || "Equipo Local"}</span>
                                            </div>
                                            <span className="vs">vs</span>
                                            <div className="equipo">
                                                <img
                                                    src={partido.visitante?.imagen || "/assets/images/default.png"}
                                                    alt={partido.visitante?.nombre || "Equipo Visitante"}
                                                    className="escudo"
                                                />
                                                <span>{partido.visitante?.nombre || "Equipo Visitante"}</span>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                                <div className="navegacion-jornadas">
                                    <button onClick={anteriorJornada} disabled={jornadaActual === 0}>
                                        ⬅ Anterior
                                    </button>
                                    <button
                                        onClick={siguienteJornada}
                                        disabled={jornadaActual === jornadas.length - 1}
                                    >
                                        Siguiente ➡
                                    </button>
                                </div>
                            </>
                        )}

                        {modalType === "clasificacion" && (
                            <>
                                <h2>Clasificación</h2>
                                <table className="clasificacion-detalle">
                                    <thead>
                                        <tr>
                                            <th>#</th>
                                            <th>Equipo</th>
                                            <th>PJ</th>
                                            <th>V</th>
                                            <th>E</th>
                                            <th>D</th>
                                            <th>GF</th>
                                            <th>GC</th>
                                            <th>DG</th>
                                            <th>Puntos</th>
                                            <th>Últimos 5</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {clasificacion.map((equipo, index) => (
                                            <tr
                                                key={equipo.id}
                                                className={index >= clasificacion.length - NUMERO_DESCENSO ? "descenso" : ""}
                                            >
                                                <td>{index + 1}</td>
                                                <td className="equipo-nombre">
                                                    <img
                                                        src={equipo.imagen || "/assets/images/default.png"}
                                                        alt={equipo.nombre || "Equipo"}
                                                        className="escudo"
                                                    />
                                                    {equipo.nombre || "Equipo"}
                                                </td>
                                                <td>{equipo.partidosJugados || 0}</td>
                                                <td>{equipo.victorias || 0}</td>
                                                <td>{equipo.empates || 0}</td>
                                                <td>{equipo.derrotas || 0}</td>
                                                <td>{equipo.golesFavor || 0}</td>
                                                <td>{equipo.golesContra || 0}</td>
                                                <td>{equipo.diferenciaGoles || 0}</td>
                                                <td>{equipo.puntos || 0}</td>
                                                <td className="ultimos-resultados">
                                                    {equipo.ultimosResultados?.map((resultado, i) => (
                                                        <span
                                                            key={i}
                                                            className={`resultado ${
                                                                resultado === "W"
                                                                    ? "win"
                                                                    : resultado === "D"
                                                                    ? "draw"
                                                                    : "loss"
                                                            }`}
                                                        >
                                                            {resultado === "W" ? "✔" : resultado === "D" ? "⚪" : "❌"}
                                                        </span>
                                                    )) || "N/A"}
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </>
                        )}
                    </div>
                </div>
            )}
        </div>
    );
}

export default LeagueMenu;
